// LESSON: List API - Reference Page 2.
// You will learn: Use indexed list access, search, removal, sorting, and subList views.
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

class ListApiReference {
  public static void main(String[] args) {
    example1IndexedAccess();
    example2SearchAndRemove();
    example3SortCopyAndView();
  }

  static void example1IndexedAccess() {
    List<String> letters = new ArrayList<>();
    letters.add("a");
    letters.add("c");
    letters.add(1, "b");
    String first = letters.get(0);
    letters.set(0, "A");
    System.out.println(first + " " + letters);
  }

  static void example2SearchAndRemove() {
    List<String> names = new ArrayList<>(Arrays.asList("Ada", "Bo", "Ada"));
    int adaIndex = names.indexOf("Ada");
    boolean removedByValue = names.remove("Bo");
    String removedByIndex = names.remove(0);
    System.out.println(adaIndex + " " + removedByValue + " " + removedByIndex);
  }

  static void example3SortCopyAndView() {
    List<String> names = new ArrayList<>(Arrays.asList("Bo", "Ada", "Kim"));
    names.sort(Comparator.naturalOrder());
    List<String> firstTwo = names.subList(0, 2);
    firstTwo.set(1, "Ann");
    List<String> fixedSize = Arrays.asList("x", "y");
    List<String> readOnlyCopy = Collections.unmodifiableList(new ArrayList<>(names));
    System.out.println(names + " " + fixedSize + " " + readOnlyCopy);
  }
}
